#define _USE_MATH_DEFINES
#include <iostream>
#include <cmath>

class Shape {
public:
    virtual double getArea() = 0;
    virtual ~Shape() = default;
};

class Rectangle : public Shape {
private:
    double width;
    double height;
public:
    Rectangle(double w, double h) : width(w), height(h) {}
    double getArea() override { return width * height; }
};

class Circle : public Shape {
private:
    double radius;
public:
    Circle(double r) : radius(r) {}
    double getArea() override { return M_PI * radius * radius; }
};

int main() {
    Rectangle rect1(5.0, 10.0);
    std::cout << rect1.getArea() << std::endl;
    Rectangle rect2(-2.0, 5.0);
    std::cout << rect2.getArea() << std::endl;
    Rectangle rect3(10.0, -3.0);
    std::cout << rect3.getArea() << std::endl;
    Rectangle rect4(-4.0, -6.0);
    std::cout << rect4.getArea() << std::endl;
    Circle circ1(4.0);
    std::cout << circ1.getArea() << std::endl;
    Circle circ2(-3.0);
    std::cout << circ2.getArea() << std::endl;
    Rectangle rect5(0.0, 7.0);
    std::cout << rect5.getArea() << std::endl;
    Circle circ3(0.0);
    std::cout << circ3.getArea() << std::endl;
    return 0;
}
